var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"제이크?","JPN":"ジェイク？","ENG":"Jake?","TWN":"傑克？"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"오랜만에 왔어요. 어머니.","JPN":"久しぶりに戻ったよ、母さん。","ENG":"Long time no see, Mom.","TWN":"我有好久沒回來了吧，母親。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"오지 않을 줄 알았단다.","JPN":"もう来ないのかと思ったわ。","ENG":"I thought you'd never come.","TWN":"我以為你不會來了。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"네 아버진......","JPN":"あなたのお父さんは……","ENG":"Your father...","TWN":"你父親……"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"늦어서 죄송해요.","JPN":"遅くなってごめん。","ENG":"Sorry I'm late.","TWN":"對不起，我遲到了。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"혹시, 아버지의 물건은 정리된 건가요?","JPN":"もしかして、父さんの遺品を整理した？","ENG":"Did you sort out all his belongings by the way?","TWN":"父親的東西都整理好了嗎？"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"으응, 아직은 치우지 않았다.","JPN":"ううん、まだ整理してないの。","ENG":"Yes, but I haven't put them away yet.","TWN":"嗯，我還沒有收拾掉。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"서재 방에 모아뒀으니 한 번 확인해보렴.","JPN":"書斎に集めておいたから、一度確認してみなさい。","ENG":"They're all in his study, if you'd like to take a look.","TWN":"我放在書房裡了，你去確認一下吧。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"네, 고마워요.","JPN":"うん、ありがとう。","ENG":"I will. Thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"sky","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이 작은 상자에 들어있는 게 전부인가?","JPN":"この小さな箱に入ってるのが全部なのか？","ENG":"It's such a small box... Is this everything?","TWN":"這小箱子裡的就是全部了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......일평생 돈을 그렇게 열심히 벌었는데, 뭐 하나 남질 않았군요.","JPN":"……一生懸命働いて稼いだくせに、何一つ残ってないな。","ENG":"You worked so hard all your life, yet you left so little behind.","TWN":"……努力賺了一輩子錢，結果剩下的只有這些啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"음? 이 수첩은...... 아버지가 쓰던 일지인가.","JPN":"うん？　この手帳は……父さんが書いていた日誌か。","ENG":"Huh? This notepad... Is this his journal?","TWN":"嗯？這個筆記本……看來是父親的筆記啊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"지난 번에 있었던 남부의 대규모 침식사태 이후, 국가가 예산을 풀어 적극적으로 용병들을 불러모으기 시작했다. 한동안 꽤 바빠질 예정이다.","JPN":"先日起きた南部での大規模侵食事態以後、国が予算を投入して積極的に傭兵たちを呼び集めはじめた。\\nしばらくはとても忙しくなりそうだ。","ENG":"After the widespread Corruption in the south last time, the government decided to allocate funding to aggressively mobilize mercenaries. Looks like I'll be busy for a while now.","TWN":"自從上次南部遭受了大規模侵蝕，國家開始投入預算積極召集傭兵。看來會忙上一段時間了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"스무 명 정도의 아이들을 난민지구로 호송하는 동안, 또 다시 중규모의 침식사태가 일어났다.","JPN":"20人あまりの子供たちを難民地区に護送する間、再び中規模侵食事態が発生した。","ENG":"While we escorted around two dozen children to the refugee district, another mid-scale Corruption Disaster took place.","TWN":"護送20名左右的孩子到難民區域，期間又發生了中規模侵蝕。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"도시외곽의 난민들은 언제나 위험에 노출되어있고, 방위군은 ‘균열’을 막아내느라 내부에 신경 쓸 전력이 부족하다.","JPN":"都市近郊にいる難民たちは常に危険にさらされていて、\\n防衛軍は「亀裂」を防ぐことに精一杯だから内部を取りまとめる戦力が足りない。","ENG":"The refugees in the city outskirts are always vulnerable, while the defending forces are too preoccupied with keeping the \\"Rift\\" sealed to attend to the city.","TWN":"城市週邊的難民隨時暴露在危險之中，防衛軍則要阻止''裂變''，根本沒有多餘戰力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"최근 들어 난기류가 잦다. 대낮에 하늘이 붉게 물들기도 한다. 침식지역 일대는 이런 이변현상이 심하다던데.","JPN":"最近になって乱気流が頻繁に発生している。昼間に空が赤く染まる日もあった。\\n侵食地域一帯ではこのような異変現象がひどいらしい。","ENG":"Turbulence comes often recently. The sky turns red in mid-day sometimes. I heard such disturbances are severe in the disaster zones.","TWN":"最近發生很多亂流。在日光下天空被染成了紅色，聽說侵蝕區域內這種異常現象更加嚴重。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 육로를 통하는 것은 훨씬 위험하기 때문에 선택의 여지가 없다.","JPN":"しかし、陸路で渡ることはもっと危険だから他に選択肢はない。","ENG":"But we have no choice but to fly, as ground movement is even more dangerous.","TWN":"但是現在走陸路更危險，我別無選擇。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"제이크와 함께 캠핑을 왔다. 간만의 휴가인 만큼 소중하게 느껴진다.","JPN":"ジェイクと一緒にキャンプをした。久々の休暇だけあって大切なひと時を過ごせた。","ENG":"I came camping with Jake. This day feels extra precious as it's been so long since I've been on leave.","TWN":"和傑克一起去露營了。因為是難得的假期，所以感覺格外珍貴。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그 아이는 이곳에서 지평선의 저무는 노을 구경하는 게 가장 좋다고 했다.","JPN":"ジェイクはここで太陽が地平線に沈む頃の夕暮れを見ることが一番好きだと言った。","ENG":"Jake says he loves watching the sunset over the horizon here.","TWN":"那孩子說在這裡看地平線晚霞是最棒的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"맥주를 나눌 수 있는 나이가 되면, 다시 함께 오고 싶은 장소.","JPN":"ビールを飲み交わせる年になったら、また一緒に来たい場所だ。","ENG":"I'd love to come back here with him when he's old enough to have a beer with me.","TWN":"等他再長大些可以與我一起喝酒了，希望能和他再來一次這裡。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"비행기를 띄울 파일럿이 부족한 형편이다. 하늘을 나는 침식체에 대한 소문 때문에, 다들 의뢰를 쉬쉬하고 있다.","JPN":"飛行機を操縦できるパイロットが足りない状況だ。\\n空を飛ぶ侵食体の噂のせいか、誰もが依頼を受けたがらなくなった。","ENG":"We're short on pilots for the aircraft. Everyone's reluctant to take the job due to the rumors of flying C.O.s.","TWN":"目前缺少可以駕駛飛機的飛行員。因為有傳聞說空中出現過侵蝕體，導致大家都不敢隨便接受委託。"},"stage":{"bg":"WARZONE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"이 전쟁이 종말까지 이어질 거라는 불안이 겉잡을 수 없이 퍼지고 있다.","JPN":"この戦争が終末に繋がっているという不安がどんどん広がっている。","ENG":"More people are growing anxious that this war may mean the end of humanity as we know it.","TWN":"也許這場戰爭永遠也不會結束，如此種種不安情緒正在逐漸蔓延。"},"stage":{"bg":"WARZONE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"한 꼬마가 내게 고맙다며 초콜렛을 줬다. 제이크와 키가 비슷했다. 아니, 제이크가 더 컸던가. 하루가 다르게 변해가던 아들의 모습이 지금은 어떤지 모르겠다.","JPN":"ある子供がお礼のチョコレートをくれた。ジェイクと背が同じくらいだった。いや、ジェイクのほうが高かったか。\\n毎日のように背が伸びてた息子は、今どんな姿になっているんだろう。","ENG":"A kid gave me his chocolate to thank me. He was about as tall as Jake. Wait, maybe Jake was taller. I wonder what my son looks like right now. He's growing up so fast.","TWN":"有個孩子給我一塊巧克力做謝禮。他身高和傑克差不多。不，傑克應該更高些。兒子長得可快了，真不知道他現在是什麼模樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"아직도 침식지대엔 무수히 많은 실종자가 있다. 내가 구하지 않으면, 그들은 남겨진 채 죽어가겠지. 내일도 바쁜 하루가 될 듯 하다.","JPN":"未だに侵食地帯には多数の行方不明者がいる。俺が助けないと、彼らは残されたまま死んでいくだろう。\\n明日も忙しい一日になりそうだ。","ENG":"There are still many people who remain missing in the Corrupted Areas. They'll probably die there if I don't save them. Looks like it's going to be another busy day tomorrow.","TWN":"侵蝕地區仍有無數的失蹤人員。如果我不去救援的話，等待他們的就只有死亡。明天又將是忙碌的一天。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체에게 꼬리를 잡히는 바람에 비상착륙을 했다. 다행히 사상자는 없고, 녀석도 쫓아오지 않는다. 우리는 육로를 통해 이 침식지대를 벗어나기로 했다.","JPN":"侵食体にばれてしまって緊急着陸させた。幸いなことに死傷者はなく、あいつらも追ってこない。\\n我々は陸路を経由してこの侵食地帯を抜け出ることにした。","ENG":"We had to perform an emergency landing because a C.O. got our tail. Fortunately there are no casualties. The C.O. hasn't pursued us either. We decided to leave this Corrupted Area via the ground.","TWN":"被侵蝕體發現了，所以只能緊急著陸。幸好沒有造成人員傷亡，那傢伙也沒追上來。我們決定通過陸路脫離這個侵蝕地區。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"빠져 나오는데 닷새가 걸렸다. 드디어 집으로 돌아갈 수 있다. 침식체 군락을 지나오며 죽을 위기를 수백 번은 거친 것 같다.","JPN":"侵食地帯を抜け出るのに5日もかかった。これでようやく家に帰れる。\\n侵食体の群れを通り過ぎる途中、数百回も死の危険を感じた。","ENG":"It took us five days to get out of there. We can finally return home. I must've had a hundred brushes with death while we passed through the C.O. cluster.","TWN":"花了五天時間才脫離，終於可以回家了。途中經過侵蝕體的群落，感覺自己幾乎經歷了數百次死裡逃生。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"살아있음에 감사할 따름이다. 돌아갈 곳이 있다는 것에 삶의 소중함을 느낀다.","JPN":"生きていることに感謝しかない。帰れる場所があるからこそ生の大切さを感じる。","ENG":"I'm just thankful that I'm alive. I'm grateful that there's a place I can return to in one piece.","TWN":"感謝上天，我還活著。因為有可以回去的地方，所以我能感受到生命的可貴。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"아버지가 돌아가셨다. 부고소식조차 접하지 못했다. 떠나는 게 아니었는데, 어리석었다.","JPN":"父が亡くなった。訃報すら届いてない。\\n離れるべきではなかった。自分が愚かだった。","ENG":"My father passed away. I didn't even hear the news right away. I should have never left my family. I'm such a fool.","TWN":"父親去世了。我連訃告都沒收到。我不該離開的，我怎麼這麼愚蠢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들을 구하면서, 나는 내가 영웅이라도 되는 착각을 하고 있었는데. 정작 가족을 지키지 못했다.","JPN":"人々を救いながら、俺は英雄にもなったと勘違いしていたが、本当に大切な家族を守ることはできなかった。","ENG":"I thought I had become some kind of a hero because I was saving people... But I failed to protect my own family.","TWN":"救人的時候我還誤以為自己是英雄，結果卻沒能守護最重要的家人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"아내가 제이크의 소식을 전해줬다. 요즘은 군인이 되겠다며 여러 모로 준비를 하는 모양이다.","JPN":"妻がジェイクの近況を教えてくれた。最近は軍人になるとか言い出して、いろいろ準備しているようだ。","ENG":"My wife updated me on how Jake's been doing. Apparently he's getting ready to join the military.","TWN":"妻子告訴我傑克的消息。妻子說他要成為一名軍人，最近好像在為此做各種各樣的準備。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"대견하다고 말해주고 싶은데, 차마 그 앞에 모습을 드러낼 수가 없었다. 내겐 그럴 자격이 없다.","JPN":"偉いな、と言ってあげたいが、どうしても息子の前に姿を現すことができなかった。\\n俺にはそんな資格はない。","ENG":"I wish I could tell him I'm proud of him, but I can't muster the courage to appear in front of him. I don't deserve to see my son.","TWN":"我想親口告訴兒子他很了不起，但我實在無法面對他。我沒有資格。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"침식증후군에 대한 의사의 소견을 들었다. 아무런 대책 없이 침식지대를 드나들던 나와 몇몇 동료들은 아주 천천히, 혹은 빠르게 몸이 굳어가고 있다.","JPN":"侵食症候群について医師の所見を聞いた。\\n何の対策も施さずに侵食地帯に出入りした俺と数人の仲間たちはゆっくり、あるいは急速に身体を蝕んでいる。","ENG":"The doctor gave me the diagnosis on the Corruption Syndrome. My colleagues and I had frequented Corrupted Areas far too often. Now our bodies are starting to stiffen at varying rates.","TWN":"我聽了醫生對於侵蝕症候群的意見。在沒有任何防護措施的情況下出入侵蝕地區，我和同事的身體都以或快或慢的速度開始僵硬化。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 유예의 시간 동안, 나는 다시 일을 시작하기로 했다.","JPN":"余命が尽きるまで、また仕事を始めることにした。","ENG":"I decided to start working again in whatever time I've got left.","TWN":"在最後所剩不多的時間裡，我決定重新開始工作。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘은 좋은 날이다. 총 쏘는 걸 싫어하던 그 아이가 벌써 소위 약장을 달게 되다니. 그저 자랑스러울 따름이다.","JPN":"今日はいい日だ。銃の扱いが苦手だったあの子が早くも少尉に昇進するなんて。誇らしい限りだ。","ENG":"It's a great day today. I can't believe the boy who hated shooting is about to become a lieutenant. I'm so proud of my son.","TWN":"今天是個好日子。那孩子曾經討厭開槍，現在居然已經穿上少尉的軍裝了。我感到非常驕傲。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"난 아내가 보내준 아들의 진급 사진을 인화해서 액자로 만들었다. 아들의 웃는 모습을 오랜만에 볼 수 있었다.","JPN":"俺は妻が送ってくれた昇進するときの息子の写真を額縁に入れた。\\n久々に息子の笑顔が見れてよかった。","ENG":"My wife sent me a picture of him in uniform. I had it printed and framed. It's been so long since I've seen him smile.","TWN":"妻子發來了兒子的晉升照，我把它印出來放進相框。久違地看到了兒子的笑容。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"일을 계속할 수가 없어 은퇴를 결정했다. 의사가 말한 것보다 훨씬 오래 버티긴 했지만, 이렇게 펜을 쥘 날도 얼마 남지 않은 듯 하다.","JPN":"仕事を続けることができなくなって引退することにした。\\n医師が言ってた日より、ずっと長く耐えてきたが、こうしてペンを握れる日もあとわずかだろう。","ENG":"My body won't let me work anymore. So I decided to retire. Although I lasted a lot longer than my doctor predicted, I don't think I'll be writing many more of these entries from now on.","TWN":"無法繼續工作了，我決定退休。雖然我比醫生預計的多撐了很久，但能像現在這樣拿筆的日子似乎也不剩多少了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"아내가 문병을 왔다. 몰랐으면 했지만, 입 싼 동료 놈이 주소를 불었던 모양이다.","JPN":"妻が見舞いに来てくれた。知らせたくなかったが、口の軽い仲間が住所を教えたようだ。","ENG":"My wife paid me a visit. As much as I tried to stay out of my family's way, I guess one of the guys with loose lips told her my address.","TWN":"妻子來探病了。雖然並不想讓她知道，但好像嘴碎的同事把地址告訴她了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"오랫동안 얼굴을 마주보며 얘길 나눴다. 제이크에 대해 많이 물어봤다. 처음엔 걱정했는데, 카운터가 된다는 게 그리 나쁘지만은 않은 일 같았다.","JPN":"久しぶりにちゃんと向き合って話をした。ジェイクについていろいろ聞いてみた。\\n最初は心配したが、カウンターになることってそんなに悪くはないかもしれないと思った。","ENG":"After so many years of being apart, we were talking face to face again. I asked a lot about Jake. At first I was worried for him, but now it seems like becoming a Counter is not all that bad.","TWN":"我們面對面聊了很久。我問了很多關於傑克的問題。剛開始我很擔心他，但現在看來，似乎成為制裁者並不是件壞事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"제이크. 어쩌면 이게 마지막 편지가 될 거다. 네가 이걸 읽진 않겠지만, 이 말은 전하고 싶구나.","JPN":"ジェイク。これが最後の手紙になるだろう。\\nお前がこれを読んでくれるのかわからないが、この言葉だけは伝えておきたい。","ENG":"Jake. This may be my last letter to you. You'll probably never read this, but I wanted to tell you this.","TWN":"傑克。也許這是最後一封信了。雖然你可能不會讀到這封信，但我還是想說啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"난 그날 이후로 평생 날 미워하며 살아왔지. 하지만 단 한시도 널 잊은 적이 없다.","JPN":"俺はあの日以来、自分を責め続けながら生きてきた。だが、一日もお前を忘れたことはない。","ENG":"You probably hated me all your life, ever since that day. But I never forgot about you.","TWN":"從那天起我就一直憎恨自己，但我從來沒有忘記過你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"용서는 바라지 않으마. 그리고......","JPN":"許してくれとは言わない。そして……","ENG":"I don't expect you'd ever forgive me. But...","TWN":"我不期望你會原諒我，不過……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"멋지게 자라줘서 고맙다.","JPN":"立派に育ってくれて、ありがとう。","ENG":"Thank you for growing up to be such a fine young man.","TWN":"謝謝你能長得這麼英俊又優秀。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......아버지.","JPN":"……父さん。","ENG":"Dad...","TWN":"……父親。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"전 아버지를 용서할 수가 없어요.","JPN":"俺は父さんを許せない。","ENG":"I can't forgive you.","TWN":"我是不會原諒父親的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"처음부터, 아무 것도 용서할 필요가 없었거든요.","JPN":"最初から、許すようなことなんて何もなかったから。","ENG":"Because there was nothing to forgive you for in the first place.","TWN":"因為一開始，就沒有什麼需要我原諒的事。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"죄송해요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"제가 먼저 찾아갔어야 했는데.","JPN":"俺の方から尋ねるべきだった。","ENG":"I should've visited you first.","TWN":"明明我應該先去看您的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이제 편히 쉬세요.","JPN":"どうか、安らかに。","ENG":"Rest in peace now.","TWN":"現在請好好休息吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아버지가 못다한 일은...... 제가 이어나갈 테니까.","JPN":"父さんがやり残した仕事は……俺が受け継ぐから。","ENG":"What you never got to finish... I will continue instead.","TWN":"父親沒有做完的事情……我會替您繼續下去的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};